mapper.select:
SELECT
    SUM(totalCount) as totalCount,sum(openCount) as openCount,sum(useCount) as useCount,
    sum(case when status = 0 and work_status = 0 and order_permission = 0 then 1 else 0 END) as acceptCount
FROM(
    SELECT b.user_id,b.order_permission,b.`status`,b.work_status,count(id) as totalCount,
    sum(case when a.`status` = 0 then 1 else 0 end)as openCount,
    sum(case when a.`status` = 0 and a.del_flag = 0 and b.order_permission = 0 and b.work_status = 0 and b.`status` = 0  then 1 else 0 end)as useCount
    FROM ct_merchant_qrcode a
    JOIN ct_merchant b on a.merchant_id = b.user_id
    WHERE b.del_flag = 0

        and b.agent_id = #{dto.agentId}


        and a.nick_name like concat('%',#{dto.nickName},'%')


        and a.account_number like concat('%',#{dto.accountNumber},'%')


        and a.agent_id = #{dto.agentId}


        and a.channel_id = #{dto.channelId}


        and b.status = #{dto.status}


        and b.del_flag = #{dto.delFlag}

    GROUP BY b.user_id,b.order_permission,b.`status`,b.work_status
)m
